$adminTitle='Manage Kids Courses';require_once __DIR__.'/../includes/kids-admin-header.php';$message='';
if($_SERVER['REQUEST_METHOD']==='POST'&&verify_csrf($_POST['csrf_token']??null)){
  $action=(string)($_POST['action']??'save');$id=(int)($_POST['id']??0);
  if($action==='delete'&&$id){$pdo->prepare('DELETE FROM kids_courses WHERE id=?')->execute([$id]);header('Location: kids-courses.php');exit;}
  $data=['title'=>trim((string)$_POST['title']),'slug'=>slugify(trim((string)($_POST['slug']?:$_POST['title']))),'short'=>trim((string)$_POST['short_description']),'description'=>trim((string)$_POST['description']),'age'=>in_array($_POST['age_group'],['6-8','9-12','13-15','All'],true)?$_POST['age_group']:'All','difficulty'=>trim((string)$_POST['difficulty']),'duration'=>trim((string)$_POST['duration']),'icon'=>trim((string)$_POST['icon']),'color'=>preg_match('/^#[0-9a-f]{6}$/i',(string)$_POST['theme_color'])?$_POST['theme_color']:'#6757f5','outcomes'=>trim((string)$_POST['learning_outcomes']),'status'=>$_POST['status']==='Draft'?'Draft':'Published','sort'=>(int)$_POST['sort_order']];
  if($id){$s=$pdo->prepare('UPDATE kids_courses SET title=:title,slug=:slug,short_description=:short,description=:description,age_group=:age,difficulty=:difficulty,duration=:duration,icon=:icon,theme_color=:color,learning_outcomes=:outcomes,status=:status,sort_order=:sort WHERE id=:id');$data['id']=$id;$s->execute(array_combine(array_map(fn($k)=>':'.$k,array_keys($data)),array_values($data)));}
  else{$s=$pdo->prepare('INSERT INTO kids_courses (title,slug,short_description,description,age_group,difficulty,duration,icon,theme_color,learning_outcomes,status,sort_order) VALUES (:title,:slug,:short,:description,:age,:difficulty,:duration,:icon,:color,:outcomes,:status,:sort)');$s->execute(array_combine(array_map(fn($k)=>':'.$k,array_keys($data)),array_values($data)));}
  header('Location: kids-courses.php?saved=1');exit;
}
$edit=!empty($_GET['edit'])?kids_course($pdo,(int)$_GET['edit']):null;$showForm=$edit||isset($_GET['new']);$courses=kids_courses($pdo,false);
?>
