':''?>>Published</option><option <?=($edit['status']??'')==='Draft'?'selected':''?>>Draft</option></select></label><div class="wide"><button class="btn btn-premium" name="action" value="save">Save course</button> <a class="btn btn-outline-light" href="kids-courses.php">Cancel</a></div></form><?php endif?>
